import React, {useEffect, useRef, useState} from 'react';
import axios from "axios";

function User(props){
    const {isPreferencesEnable, onPreferencesChange, userData, onLogout} = props;
    const [aberto, setAberto] = useState(isPreferencesEnable);
    const menuRef = useRef(null);
    const [showEdit, setShowEdit] = useState(false);
    const [selectedFile, setSelectedFile] = useState(null);
    const [menuType, setMenuType] = useState("profile");
    const [isEditing, setIsEditing] = useState(false);
    const [error, setError] = useState('');

    useEffect(() => {
        setAberto(isPreferencesEnable);
    },[isPreferencesEnable]);

    useEffect(() => {
        //setAberto(isPreferencesEnable);
        const handleClickOutside = (event) => {
            if (aberto && menuRef.current && !menuRef.current.contains(event.target)) {
                onPreferencesChange(false);
                setAberto(false);
            }

        };
        document.addEventListener("mousedown", handleClickOutside);
        return () => {
            document.removeEventListener("mousedown", handleClickOutside);
        };
    });

    const onProfilePictureUpload = () => {
        const formData = new FormData();
        formData.append(
            "picture",
            selectedFile/*,
            selectedFile.name*/
        );
        console.log(formData);
    }

    const handleEditing = () => {
        if(isEditing){
            setIsEditing(false);
        } else
            setIsEditing(true);
    }

    const handleProfileName = async (event) => {
        event.preventDefault()
        try {
            const response = await axios.put('http://localhost:8080/update',{
                profileName: "",
                profileImage: ""
            });

        }catch (error) {}
    }

    return (
        <div
            ref={menuRef}
            className={`user-card position-absolute top-50 start-0 p-2 ${isPreferencesEnable ? "open" : ""}`}
        >
            <div className="user-card-sidebar">
                <div className="user-settings-container">
                    <ul className="user-settings">
                        <li className="user-settings-item">
                            <div>
                                <button
                                    className="general-button"
                                    onClick={() => {
                                        setMenuType("general")
                                    }}
                                >
                                    <i className="bi bi-laptop"></i>
                                    General
                                </button>
                            </div>
                        </li>
                        <li className="user-settings-item">
                            <div>
                                <button
                                    className="account-button"
                                    onClick={() => {
                                        setMenuType("account")
                                    }}
                                >
                                    <i className="bi bi-key"></i>
                                    Account
                                </button>
                            </div>
                        </li>
                        <li className="user-settings-item">
                            <div>
                                <button
                                    className="appearance-button"
                                    onClick={() => {
                                        setMenuType("appearance")
                                    }}
                                >
                                    <i className="bi bi-brush"></i>
                                    Appearance
                                </button>
                            </div>
                        </li>
                        <li className="user-settings-item">
                            <div>
                                <button
                                    className="help-button"
                                    onClick={() => {
                                        setMenuType("help")
                                    }}
                                >
                                    <i className="bi bi-info-circle"></i>
                                    Help
                                </button>
                            </div>
                        </li>
                    </ul>
                </div>
                <div className="user-settings-item">
                    <div className="user-settings-item-content">
                        <button
                            className="profile-button"
                            onClick={() => {
                                setMenuType("profile")
                            }}
                        >
                            <i className="bi bi-person-circle"></i>
                            Profile
                        </button>
                    </div>
                </div>
            </div>
            <div className="user-card-container" hidden={menuType !== "profile"}>
                <div className="user-card-settings">
                    <div className="user-picture-container"
                         onMouseEnter={() => {
                             setShowEdit(true);
                         }}
                         onMouseLeave={() => {
                             setShowEdit(false);
                         }}
                    >
                        {showEdit && (<i className="bi bi-pencil"></i>)}
                        {userData && (
                            <div className="change-profile-picture-button">
                                <input
                                    className=""
                                    id="profile-picture-upload"
                                    style={{display: "none"}}
                                    type="file"
                                    onChange={onProfilePictureUpload}
                                ></input>
                                <img
                                    className="user-picture"
                                    src={userData.imagePath}
                                    alt="">
                                </img>
                                <label className="change-profile-picture" htmlFor="profile-picture-upload"></label>
                            </div>
                        )}
                    </div>
                    <div className="user-card-name">
                        {userData && (
                            isEditing ? (
                                    <input
                                        type="text"
                                        value={userData.name}
                                        className="user-card-name-input"
                                    ></input>
                                ): (
                                <h4 className="user-name-title">
                                    {userData.name}
                                </h4>
                            )
                        )}
                        <button
                            className="user-card-name-button"
                            onClick={() => {setIsEditing(true)}}>
                            <i className="bi bi-pencil"></i>
                        </button>
                    </div>
                    <div className="user-card-description">
                        <h5 className="user-card-description-subtitle">About</h5>
                        <div className="user-card-description-content">
                            {userData && (
                                <p className="user-description">
                                    {userData.description}
                                </p>
                            )}
                            <button className="user-card-description-button" onClick={() => {
                            }}>
                                <i className="bi bi-pencil"></i>
                            </button>
                        </div>
                    </div>
                </div>
                <div className="user-card-session">
                    <button
                        className="logoff-button"
                        onClick={() => {
                            onLogout();
                            setAberto(false);
                            onPreferencesChange(false);
                        }}
                    >
                        Log Off
                    </button>
                </div>
            </div>
            <div className="general-card-container" hidden={menuType !== "general"}>
                <div className="general-card-content">
                    <h4 className="general-card-title">General</h4>
                    <h5 className="general-card-subtitle">Language</h5>
                    <select className="general-card-language">
                        <option value="English">English</option>
                        <option value="Spanish">Spanish</option>
                        <option value="Portuguese">Portuguese</option>
                    </select>
                </div>
            </div>
            <div className="account-card-container" hidden={menuType !== "account"}>
                <h4>ACCOUNT</h4>
            </div>
            <div className="appearance-card-container" hidden={menuType !== "appearance"}>
                <h4>APPEARANCE</h4>
            </div>
            <div className="help-card-container" hidden={menuType !== "help"}>
                <div className="help-card-content">
                    <h4 className="help-card-title">HELP</h4>
                    <h5 className="help-card-subtitle">LusApp</h5>
                    <p className="help-card-subtitle">Version 0.2025.0.1</p>
                </div>
            </div>
        </div>
    );
}

export default User;
